option.value:
body {
    font-family: 'Chelsea Market', cursive;
    font-family: 'Dosis', sans-serif;
}

h2 {
    font-size: 36px;
    font-weight: 600;
}

.font-16 {
    font-size: 16px;
    font-weight: 400;
}

.text-orange {
    color: #f04c26;
}

a {
    text-decoration: none !important;
}

li {
    list-style-type: none;
}
img{
    max-width: 100%;
    height: auto;
}


/*======BANNER CSS STARTS====*/

.banner-heading h2 {
    text-align: center;
    position: relative;
    margin: 70px auto;
    max-width: 130px;
    width: 100%;
}

.banner-heading h2::after {
    border-top: 2px solid #F04C26;
    width: 70px;
    position: absolute;
    content: " ";
    top: 22px;
    left: -80px;
}

.banner-heading h2::before {
    border-top: 2px solid #F04C26;
    width: 70px;
    position: absolute;
    content: " ";
    top: 22px;
    right: -80px;
}


/*======BANNER CSS ENDS====*/


/*======HEADER CSS STARTS=======*/

.header .navbar-toggle {
    border: 0;
    right: -210px;
    top: 2px;
}

.header .navbar-brand>img {
    margin-top: -10px;
}

.header .navbar-default .navbar-toggle .icon-bar {
    background-color: #F04C26;
}

.header .navbar-default .navbar-toggle:focus,
.header .navbar-default .navbar-toggle:hover {
    background-color: transparent;
}

.header {
    background-image: url('../images/facility-showcase/TestingMod.jpg');
    /*height: 645px;*/
    /*background-position: center;*/
    /*background-repeat: no-repeat;*/
    /*background-size: 100% auto;*/
    height: clamp(560px, 82vh, 820px);
    background-size: cover;
    background-position: center 30%; /* sposta il punto focale */


}

.header .navbar-default {
    background-color: transparent;
    border: 0;
    padding-top: 15px;
    max-width: none;
    margin-right: 0;
    position: relative;
}

.header .navbar-default .navbar-form.navbar-right {
    margin: 0;
    padding-right: 0;
    position: absolute;
    right: 0;
    top: 8px;
}

.header .navbar-default .navbar-form.navbar-right .input-group {
    display: flex;
    align-items: stretch;
    background: #ffffff;
    border-radius: 999px;
    box-shadow: 0 10px 24px rgba(0, 0, 0, 0.16);
    overflow: hidden;
}

.header .navbar-default .navbar-form.navbar-right .form-control {
    border: 0;
    box-shadow: none;
    height: 40px;
    padding: 8px 16px;
    font-size: 14px;
}

.header .navbar-default .navbar-form.navbar-right .btn {
    border: 0;
    background-color: #f04c26;
    color: #fff;
    height: 40px;
    padding: 0 16px;
}

.header .navbar-default .navbar-form.navbar-right .btn:hover {
    background-color: #d74320;
}

.header .navbar-default .navbar-form.navbar-right .fa {
    font-size: 16px;
}

.header .navbar-default .navbar-nav>li>a {
    color: #414141;
    font-size: 16px;
    font-weight: 500;
}

.header .navbar-default .navbar-nav>li>a:hover {
    color: #f04c26;
}

.header .navbar-default .navbar-nav>li>a.navbar-profile-link {
    display: inline-flex;
    align-items: center;
    gap: 8px;
}

.navbar-profile-avatar {
    width: 28px;
    height: 28px;
    border-radius: 50%;
    object-fit: cover;
    border: 1px solid #d6dce8;
}

.header .banner {
    cursor: grab;
    position: relative;
    min-height: 100%;
    display: flex;
    align-items: center;
    overflow: hidden;
    padding: 12px 0;
    background: transparent;
}

.header .banner::before {
    display: none;
}

.header .banner .banner-content {
    position: relative;
    z-index: 1;
}

.header .banner .banner-content .item {
    max-width: 760px;
    margin: 0 auto;
    padding: 0;
    border-radius: 0;
    background: transparent;
    border: 0;
    box-shadow: none;
    -webkit-backdrop-filter: none;
    backdrop-filter: none;
}

.header .banner .banner-content h1 {
    color: #f5f9f5;
    font-size: 72px;
    text-transform: uppercase;
    font-family: 'Dosis', sans-serif;
    font-weight: 800;
    letter-spacing: 0.04em;
    margin: 0 0 22px;
    text-align: left;
    line-height: 1.04;
}

.header .banner .banner-content .owl-prev {
    position: absolute;
    left: -14px;
    top: 50%;
    transform: translateY(-50%);
    background: rgba(255, 255, 255, 0.25) url("../images/arrow-leftBlack.png") center center no-repeat !important;
    font-size: 0 !important;
    height: 44px;
    width: 44px;
    border-radius: 999px;
    border: 1px solid rgba(255, 255, 255, 0.35);
    content: "";

}

.header .banner .banner-content .owl-next {
    background: rgba(255, 255, 255, 0.25) url("../images/arrow-rightBlack.png") center center no-repeat !important;
    content: "";
    font-size: 0 !important;
    height: 44px;
    position: absolute;
    right: -14px;
    top: 50%;
    transform: translateY(-50%);
    width: 44px;
    border-radius: 999px;
    border: 1px solid rgba(255, 255, 255, 0.35);
}

.header .banner .banner-content .owl-theme .owl-dots {
    display: none;
}
#header {
	height: auto;
	background-size: 100%;
	background-color: rgba(240, 76, 37, 0.1);
	background-image: url('../images/pattern-xv.png');
    font-family: 'Dosis', sans-serif;
}

/*======HEADER CSS ENDS====*/


/*====ABOUT CSS STARTS====*/

.about {
    background-color: #fff;
    margin-bottom: 65px;
}

.about .banner-heading p {
    color: #555655;
    padding: 0 200px 30px 200px;
    text-align: center;
    line-height: 26px;
}

.about .about-inner-content {
    text-align: center;
}

.about .about-inner-content p {
    font-size: 18px;
    text-transform: uppercase;
    font-weight: 500;
}

.about .about-image {
    text-align: center;
    margin-bottom: 10px;
}


/*======ABOUT CSS ENDS====*/


/*====VIDEO CSS STARTS====*/

.video {
    background-image: url(../images/banner-2.jpg);
    height: 450px;
    position: relative;
    background-repeat: no-repeat;
    background-position: center;
}

.video::after {
    position: absolute;
    background-color: rgba(0, 0, 0, 0.7);
    height: 100%;
    width: 100%;
    left: 0;
    top: 0;
    content: " ";
}

.video .play-video {
    text-align: center;
    margin-top: 170px;
}

.video .play-video img {
    position: relative;
    z-index: 1;
}

.video .play-video p {
    font-size: 28px;
    font-weight: 500;
    z-index: 999;
    color: #fff;
    position: relative;
    margin-top: 50px;
}

/*======VIDEO CSS ENDS====*/


/*====TRAIL CSS STARTS====*/

.trails .accordion1 {
    margin-left: 160px;
}

.trails .container-fluid {
    padding-right: 0;
    overflow: hidden;
    background-color: #f1f0f0;
}

.trails .panel-default>.panel-heading {
    background-color: #F04C26;
    color: #fff;
    border: 0;
    border-radius: 0;
    margin-bottom: 20px;
}

.trails .panel-title {
    font-size: 24px;
}

.trails .panel-group .panel {
    margin-bottom: 0;
    border-radius: 4px;
    border: 0;
}
/*DDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDC0*/
.trails .accordion1 p {
    font-size: 16px;
    color: #555655;
    background-color: #fff;
    margin: 0;
    padding: 15px;
    margin-bottom: 20px;
}

.trails .panel-default>.panel-heading+.panel-collapse>.panel-body {
    border: 0;
}

.trails .panel {
    background-color: transparent;
}

.trails .panel-body {
    padding: 0;
}


/*======TRAILS CSS ENDS====*/


/*====GALLERY CSS STARTS====*/

.gallery {
    padding-bottom: 80px;
}

.gallery .gallery-image-2 {
    margin-top: 40px;
}

.gallery .gallery-image:hover .gallery-overlay,
.gallery .gallery-image-2:hover .gallery-overlay {
    opacity: 1;
    transition: all 0.3s ease-in-out;
    visibility: visible;
}

.gallery .gallery-image,
.gallery .gallery-image-2 {
    position: relative;
    display: inline-block;
}

.gallery .gallery-overlay {
    position: absolute;
    background: rgba(0, 0, 0, 0.72);
    z-index: 1;
    height: 100%;
    width: 100%;
    opacity: 0;
    visibility: hidden;
}

.gallery .gallery-overlay a {
    text-align: center;
}

.gallery .gallery-overlay a .fa {
    font-size: 20px;
    background: #fff;
    width: 50px;
    height: 50px;
    margin: auto;
    text-align: center;
    display: inherit;
    border-radius: 100%;
    line-height: 50px;
    position: absolute;
    color: #000;
    top: 90px;
    left: 0;
    right: 0;
}


/*======GALLERY CSS ENDS====*/


/*====BLOG CSS STARTS====*/

.blog {
    background-image: url('../images/blog-banner.jpg');
    padding-bottom: 50px;
    background-size: cover;
    background-position: center;
}

.blog .blog-heading {
    font-size: 22px;
    font-weight: 600;
    text-align: center;
    margin-top: 15px;
    color: #333333;
}

.blog .blog-textual-cont {
    color: #555655;
    text-align: center;
    font-size: 16px;
    padding: 0 30px;
}

.blog .blog-img {
    text-align: center;
    position: relative;
    display: inline-block;
}

.blog .blog-img img {
    display: inline;
    margin-top: -20px;
}

.blog .blog-inner {
    background-color: #fff;
}

.blog .read-more {
    font-size: 14px;
    width: 100%;
    display: block;
    text-align: center;
    text-transform: uppercase;
    color: #f04c25;
    padding: 5px 0;
    visibility: hidden;
}

.blog .blog-inner:hover .read-more {
    visibility: visible;
}

.blog .blog-inner:hover .blog-img .img-border {
    visibility: visible;
}

.blog .blog-inner .blog-img .img-border {
    visibility: hidden;
    height: 100%;
    width: 90%;
    position: absolute;
    top: -11px;
    left: 15px;
    border: 1px solid #fff;
}


/*======BLOG CSS ENDS====*/


/*====CHALLENGE CSS STARTS====*/

.challenge {
    background-image: url('../images/bg-texture.jpg');
    padding-bottom: 80px;
}

.challenge .heading span {
    text-transform: uppercase;
    color: #f04c25;
    font-weight: 700;
}

.challenge .heading {
    max-width: 440px;
    margin: auto;
    text-align: center;
    margin-top: 90px;
}

.challenge .heading h2 {
    line-height: 70px;
}

.challenge .challenge-text .font-16 {
    font-size: 16px;
    font-weight: 400;
    color: #555655;
    padding: 40px 250px;
    text-align: center;
}

.challenge .input-group .form-control {
    border: 0;
    box-shadow: none;
    background-color: transparent;
    border-bottom: 1px solid #333;
    border-radius: 0;
    font-size: 16px;
}

.challenge .input-group {
    width: 40%;
    margin: auto;
}

.challenge .input-group .form-control:last-child,
.challenge .input-group-addon:last-child,
.challenge .input-group-btn:first-child>.btn-group:not(:first-child)>.btn,
.input-group-btn:first-child>.btn:not(:first-child),
.challenge .input-group-btn:last-child>.btn,
input-group-btn:last-child>.btn-group>.btn,
.challenge .input-group-btn:last-child>.dropdown-toggle {
    border-top-left-radius: 4px;
    border-bottom-left-radius: 4px;
    left: 30px;
}

.challenge .btn-danger {
    background-color: #f04c25;
    height: 40px;
    width: 180px;
    border: 0;
    font-size: 16px;
    font-weight: 600;
    margin-top: -7px;
}





/*======CHALLENGE CSS ENDS====*/


/*====PARTNER SECTION STARTS====*/

.partners {
    padding: 50px 0;
}

.partners .partner-images {
    text-align: center;
}

.partners .partner-images img {
    padding: 0 25px;
    display: inline-block;
}


/*====PARTNER SECTION ENDS====*/


/*====FOOTER CSS STARTS====*/

.footer {
    background-image: url('../images/immagineFooter.jpg');
    height: auto;
    position: relative;
    background-size: cover;
    font-family: 'Dosis', sans-serif;
}

.footer:after {
    position: absolute;
    background-color: rgba(56, 56, 56, 0.85);
    height: 100%;
    width: 100%;
    left: 0;
    top: 0;
    content: " ";
}

.footer p,
.footer li {
    color: #bbbbbb;
    font-size: 16px;
}

.footer .footer-content {
    position: relative;
    z-index: 1;
}

.footer .footer-content .footer-logo {
    margin-top: 60px;
}

.footer .footer-content .footer-text {
    margin-top: 30px;
}

.footer .footer-content .footer-address {
    margin-bottom: 40px;
}

.footer .footer-content .footer-address ul {
    padding: 0;
}

.footer .footer-content .footer-address ul li .fa {
    padding: 0 10px
}

.footer .footer-content .footer-address li {
    line-height: 35px;
}

.footer .footer-content .news p {
    color: #fff;
    text-transform: none;
    font-size: 22px;
    font-weight: 500;
}

.footer .footer-content .news {
    margin-top: 50px;
}

.footer .footer-content .input-group {
    display: inline-block;
    margin-top: 20px;
}

.footer .footer-content .form-control {
    height: 45px;
    border: 0;
    max-width: 300px !important;
    box-shadow: none;
}

.footer .footer-content .btn.btn-danger {
    height: 45px;
    width: 120px;
    font-size: 16px;
    background-color: #F04C25;
}

.footer .footer-content .social-icons ul {
    padding: 0;
}

.footer .footer-content .social-icons ul li {
    display: inline-block;
}

.footer .footer-content .social-icons {
    margin-top: 30px;
}

.footer .footer-content .social-icons li a .fa {
    color: #fff;
    width: 40px;
    height: 40px;
    background-color: #F04C25;
    text-align: center;
    border-radius: 100%;
    line-height: 40px;
    font-size: 20px;
    margin-right: 10px;
}

.footer .footer-content .social-icons li a {
    font-size: 18px;
    font-weight: 600;
    color: #fff;
    margin: 0 20px 0 0px;
}

.footer .footer-content .copyright {
    font-size: 12px;
    font-weight: 400;
    font-family: open sans;
    margin-top: 25px;
}

/*====ABOUT PAGE====*/
.about_wrapper {
	width: 100%;
	padding: 100px 0;
}
.about_wrapper h2 {
	font-size: 28px;
	color: #f04c25;
}
.about_wrapper p {
	font-size: 16px;
	color: #767272;
	line-height: 27px;
}
.team_wrapper h2 {
	font-size: 28px;
	color: #f04c25;
}
.team_wrapper p {
	font-size: 16px;
	color: #767272;
	line-height: 27px;
}
.team_wrapper .team_heading {
	border-bottom: 2px solid #f6f6f6;
	padding: 25px 0;
}
.team_wrapper .col-md-6 {
	margin-bottom: 50px;
}
.team_wrapper .team_heading h3 {
	font-size: 20px;
	color: #f04c25;
	margin: 0;
}
.team_wrapper .team_heading span {
	font-size: 16px;
	color: #222;
}
.our_partner_wrapper {
	padding: 70px 0;
}
.our_partner_wrapper h2 {
	font-size: 26px;
	color: #f04c25;
}
.our_partner_wrapper p {
	font-size: 16px;
	color: #7f7f7f;
	line-height: 27px;
}
.our_partner_wrapper span {
	color: #f04c25;
}
/*======FOOTER CSS ENDS====*/


/*GALLERY*/

.gallery{
    padding: 50px 0;
}
.gallery .images {
	margin: 60px 0;
}
/*GALLERY*/

/*====MEDIA QUERY STARTS====*/

@media(max-width:1199px) {
    .gallery .gallery-overlay a .fa {
        top: 65px;
    }
    .challenge .challenge-text .font-16 {
        padding: 40px 0;
    }
    .trails .accordion1 {
        margin-left: 0px;
    }
    .trails .container-fluid {
        padding-right: 15px;
    }
    .trails .trail-img {
        overflow: hidden;
    }
    .challenge .input-group {
        width: 60%;
        margin: auto;
    }
    .partners .partner-images img {
        padding: 0 15px;
    }
}

@media (max-width:991px) {
    .about .banner-heading p {
        padding: 0;
    }
    /*  .gallery .gallery-overlay {
        width: 79%;
    }*/
    .gallery .gallery-overlay a .fa {
        top: 40%;
    }
    .gallery .gallery-image {
        margin-bottom: 50px;
    }
    .blog .blog-inner {
        margin-bottom: 60px;
    }
    .header .navbar-default .navbar-form.navbar-right {
        position: static;
        margin-right: 0;
        padding-right: 15px;
    }
}

@media (max-width:767px) {
    .header .banner .banner-content .fa.fa-chevron-left {
        left: -10px;
    }
    .header .banner .banner-content .fa.fa-chevron-right {
        left: 10px;
    }
    .header .log-in {
        margin-right: 50px;
    }
    .header .banner .banner-content h1 {
        font-size: 48px;
    }
    .gallery .gallery-image {
        text-align: center;
    }
    .gallery .gallery-image img {
        display: inline;
    }
    .gallery .gallery-image-2 {
        text-align: center;
    }
    .gallery .gallery-image-2 img {
        display: inline;
    }
    .trails .trail-img img {
        max-width: 100%;
        height: auto;
    }
    .challenge .input-group {
        width: 80%;
    }
    .header .banner .banner-content .owl-prev {
        left: -2px;
    }
    .header .banner .banner-content .owl-next {
        right: -2px;
    }
    .header .banner .banner-content .item {
        padding: 24px 18px;
    }
    .custom-btn {
        width: 100%;
        min-width: 0;
        font-size: 20px;
        text-align: center;
    }
}

@media (max-width:500px) {
    .challenge .btn-danger {
        width: 110px;
    }
    .challenge .input-group .form-control:last-child,
    .challenge .input-group-addon:last-child,
    .challenge .input-group-btn:first-child>.btn-group:not(:first-child)>.btn,
    .input-group-btn:first-child>.btn:not(:first-child),
    .challenge .input-group-btn:last-child>.btn,
    .input-group-btn:last-child>.btn-group>.btn,
    .challenge .input-group-btn:last-child>.dropdown-toggle {
        left: 20px;
    }
    .footer .footer-content .social-icons ul li {
        display: block;
        margin-bottom: 10px;
    }
    .footer .footer-content .form-control {
        max-width: 170px !important;
    }
    .footer .footer-content .btn.btn-danger {
        width: 90px;
    }
}

@media (max-width:480px) {
    .gallery .gallery-overlay a .fa {
        width: 40px;
        height: 40px;
        line-height: 40px;
    }
    .gallery .gallery-overlay a .fa {
        top: 35%;
    }
}
.custom-btn{
    width: auto;
    min-width: 240px;
    font-size: 24px;
    font-weight: 700;
    margin-left: 0;
    border-radius: 999px;
    padding: 12px 32px;
    box-shadow: 0 12px 30px rgba(0, 0, 0, 0.30);
}
.center-btn{
    display: flex;
    justify-content: center;
    align-items: center;
}

/*======MEDIA QUERY ENDS====*/

